import { describe, it, expect } from 'vitest';

import {
  HookEvent,
  HOOK_CONTRACT_VERSION,
  HOOK_EVENT_NAMES,
  HOOK_EVENT_NAME_SET,
  HOOK_EVENT_SCHEMA,
  HOOK_EVENT_SCHEMAS,
  isHookEvent,
  isHookEventName,
  validateHookEvent,
} from '../src/index.js';

describe('@orchestkit/hook-contract — smoke', () => {
  it('exports the 19 known event names', () => {
    expect(HOOK_EVENT_NAMES).toHaveLength(19);
    expect(HOOK_EVENT_NAMES).toContain('SessionStart');
    expect(HOOK_EVENT_NAMES).toContain('PreToolUse');
    expect(HOOK_EVENT_NAMES).toContain('WorktreeCreate');
  });

  it('exposes a HOOK_CONTRACT_VERSION string', () => {
    expect(HOOK_CONTRACT_VERSION).toMatch(/^\d+\.\d+\.\d+/);
  });

  it('mirrors HOOK_EVENT_NAMES as a frozen Set', () => {
    for (const name of HOOK_EVENT_NAMES) {
      expect(HOOK_EVENT_NAME_SET.has(name)).toBe(true);
    }
    expect(HOOK_EVENT_NAME_SET.size).toBe(HOOK_EVENT_NAMES.length);
  });

  it('emits one JSON schema per event', () => {
    for (const name of HOOK_EVENT_NAMES) {
      const schema = HOOK_EVENT_SCHEMAS[name];
      expect(schema).toBeDefined();
      expect(schema.title).toBe(`${name} hook event`);
      expect(schema.properties?.event?.const).toBe(name);
      expect(schema.required).toContain('event');
    }
  });

  it('aggregate HOOK_EVENT_SCHEMA is a oneOf over 19 variants', () => {
    expect(Array.isArray(HOOK_EVENT_SCHEMA['oneOf'])).toBe(true);
    expect((HOOK_EVENT_SCHEMA['oneOf'] as unknown[]).length).toBe(HOOK_EVENT_NAMES.length);
  });
});

describe('isHookEventName', () => {
  it('accepts known event names', () => {
    expect(isHookEventName('SessionStart')).toBe(true);
    expect(isHookEventName('PostToolUseFailure')).toBe(true);
  });

  it('rejects unknown or non-string values', () => {
    expect(isHookEventName('SomethingElse')).toBe(false);
    expect(isHookEventName(42)).toBe(false);
    expect(isHookEventName(undefined)).toBe(false);
    expect(isHookEventName(null)).toBe(false);
  });
});

describe('validateHookEvent', () => {
  it('passes a minimal well-formed envelope', () => {
    const event: HookEvent = { event: 'SessionStart' };
    const result = validateHookEvent(event);
    expect(result.valid).toBe(true);
    if (result.valid) {
      expect(result.event).toBe('SessionStart');
    }
  });

  it('passes an envelope with optional fields', () => {
    const result = validateHookEvent({
      event: 'PreToolUse',
      timestamp: '2026-05-18T10:11:16Z',
      session_id: 'sess_abc',
      cwd: '/tmp/repo',
      payload: { tool: 'Bash' },
    });
    expect(result.valid).toBe(true);
  });

  it('rejects non-objects', () => {
    expect(validateHookEvent(null).valid).toBe(false);
    expect(validateHookEvent('SessionStart').valid).toBe(false);
    expect(validateHookEvent([]).valid).toBe(false);
    expect(validateHookEvent(undefined).valid).toBe(false);
  });

  it('rejects missing event tag', () => {
    const result = validateHookEvent({ timestamp: 'now' });
    expect(result.valid).toBe(false);
    if (!result.valid) {
      expect(result.errors.join('|')).toMatch(/missing required field: event/);
    }
  });

  it('rejects unknown event tag', () => {
    const result = validateHookEvent({ event: 'NotAReal' });
    expect(result.valid).toBe(false);
    if (!result.valid) {
      expect(result.errors.join('|')).toMatch(/unknown event tag/);
    }
  });

  it('rejects malformed optional fields', () => {
    const result = validateHookEvent({ event: 'Stop', timestamp: 12345 });
    expect(result.valid).toBe(false);
  });
});

describe('isHookEvent', () => {
  it('narrows a value when valid', () => {
    const value: unknown = { event: 'WorktreeCreate' };
    if (isHookEvent(value)) {
      // Type narrowing — value.event is HookEventName here.
      expect(value.event).toBe('WorktreeCreate');
    } else {
      throw new Error('expected narrowing');
    }
  });

  it('returns false on bad input', () => {
    expect(isHookEvent({ foo: 'bar' })).toBe(false);
  });
});
